"use client"

import * as React from "react"

import type { TabNavbarProps } from "./types"

import { cn } from "@/lib/utils"

export function TabNavbar({
  items,
  className,
  labelClassName,
  ariaLabel = "Primary navigation",
}: TabNavbarProps) {
  if (!items.length) {
    return null
  }

  return (
    <nav
      aria-label={ariaLabel}
      className={cn(
        "flex w-full flex-row items-center bg-white py-2 font-poppins",
        className,
      )}
    >
      {items.map((item, index) => {
        const key = item.id ?? `${item.label}-${index}`
        const isActive = Boolean(item.isActive)

        return (
          <button
            key={key}
            type="button"
            onClick={item.onClick}
            aria-current={isActive ? "page" : undefined}
            className={cn(
              "flex min-w-0 basis-0 flex-1 flex-col items-center justify-center gap-1 px-1 py-1 transition-colors",
              "cursor-pointer border-0 bg-transparent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-0",
              isActive
                ? "text-[#6962AC]"
                : "text-[#6B7280] hover:text-[#4B5563]",
            )}
          >
            <span
              className="flex size-6 shrink-0 items-center justify-center [&_svg]:size-6 [&_svg]:shrink-0"
              aria-hidden
            >
              {item.icon}
            </span>
            <span
              className={cn(
                "truncate text-center text-[11px] font-medium leading-4",
                labelClassName,
              )}
            >
              {item.label}
            </span>
          </button>
        )
      })}
    </nav>
  )
}

export type { TabNavbarItem, TabNavbarProps } from "./types"

import type { MouseEventHandler, ReactNode } from "react"

export type TabNavbarItem = {
  id?: string
  label: string
  icon: ReactNode
  /**
   * Mark the current section (parent-controlled), same idea as `NavbarLinkItem.isActive`.
   */
  isActive?: boolean
  onClick?: MouseEventHandler<HTMLButtonElement>
}

export type TabNavbarProps = {
  items: TabNavbarItem[]
  /**
   * Merged onto the root `<nav>`. Use for elevation when fixed to the bottom (e.g. `shadow-sm`,
   * `shadow-[0_-4px_24px_rgba(0,0,0,0.08)]`), rounding, or background overrides — no border is applied by default.
   */
  className?: string
  /**
   * Classes for every tab label (`<span>` under the icon). Defaults include size/weight/leading;
   * pass e.g. `text-sm font-semibold` to restyle all labels at once.
   */
  labelClassName?: string
  /** Passed to the wrapping `<nav>` for screen readers. */
  ariaLabel?: string
}
